{"code": "import json

# Load all business data we have
try:
    businesses_cached = locals()['var_functions.query_db:14']
except:
    businesses_cached = []

try:
    businesses_batch1 = locals()['var_functions.query_db:20']  
except:
    businesses_batch1 = []

try:
    businesses_batch2 = locals()['var_functions.query_db:26']
except:
    businesses_batch2 = []

# Combine all businesses
all_businesses = []
all_businesses.extend(businesses_cached if isinstance(businesses_cached, list) else [])
all_businesses.extend(businesses_batch1 if isinstance(businesses_batch1, list) else [])
all_businesses.extend(businesses_batch2 if isinstance(businesses_batch2, list) else [])

print(f"Total businesses available: {len(all_businesses)}")

# Count businesses with parking options
businesses_with_parking = []
for business in all_businesses:
    if not business or 'attributes' not in business or not business['attributes']:
        continue

    attributes = business['attributes']
    if attributes == 'None' or attributes is None:
        continue

    has_bike = False
    has_business = False

    # Check BikeParking
    if isinstance(attributes, dict) and 'BikeParking' in attributes:
        value = str(attributes['BikeParking']).lower().strip()
        has_bike = value == 'true'

    # Check BusinessParking
    if isinstance(attributes, dict) and 'BusinessParking' in attributes:
        parking_data = attributes['BusinessParking']
        parking_str = str(parking_data)

        # If it's a string representation of dict
        if 'True' in parking_str:
            has_business = True
        # If it's an actual dict
        elif isinstance(parking_data, dict):
            for key, val in parking_data.items():
                if str(val).lower() == 'true':
                    has_business = True
                    break

    if has_bike or has_business:
        businesses_with_parking.append({
            'business_id': business['business_id'],
            'name': business.get('name', 'Unknown'),
            'has_bike_parking': has_bike,
            'has_business_parking': has_business
        })

print(f"Businesses with parking: {len(businesses_with_parking)}")
for b in businesses_with_parking:
    print(f"  {b['business_id']}: {b['name']}")

result = {
    "total_businesses_checked": len(all_businesses),
    "businesses_with_parking": len(businesses_with_parking),
    "details": businesses_with_parking
}

print('__RESULT__:')
print(json.dumps(result))"}

