{"code": "import json

# Load all business data we have collected
all_data = []
for result_key in ['var_functions.query_db:14', 'var_functions.query_db:20', 'var_functions.query_db:26']:
    data = locals().get(result_key, [])
    if isinstance(data, list):
        all_data.extend(data)

print(f"Total businesses loaded: {len(all_data)}")

# Convert to dict by business_id for easier access
business_by_id = {}
for b in all_data:
    if b and 'business_id' in b:
        business_by_id[b['business_id']] = b

print(f"Unique business IDs collected: {len(business_by_id)}")

# Load 2018 business refs from review table
business_refs_2018 = locals()['var_functions.query_db:34']
print(f"Business refs reviewed in 2018: {len(business_refs_2018)}")

# Convert to business_id format and deduplicate
unique_business_ids_2018 = set()
for row in business_refs_2018:
    business_ref = row['business_ref']
    business_id = business_ref.replace('businessref_', 'businessid_', 1)
    unique_business_ids_2018.add(business_id)

print(f"Unique business_ids reviewed in 2018: {len(unique_business_ids_2018)}")

# Now check which ones we have parking info for
results = []
for business_id in unique_business_ids_2018:
    business = business_by_id.get(business_id)
    if not business or 'attributes' not in business or not business['attributes']:
        continue

    attrs = business['attributes']
    if attrs == 'None' or attrs is None:
        continue

    # Check parking attributes
    has_bike = False
    has_business = False

    # Check BikeParking
    if isinstance(attrs, dict):
        bike_val = attrs.get('BikeParking')
        if bike_val is not None:
            has_bike = str(bike_val).lower().strip() == 'true'

        # Check BusinessParking
        business_parking = attrs.get('BusinessParking')
        if business_parking is not None:
            parking_str = str(business_parking)
            # If it's a string representation of dict with True values
            if 'True' in parking_str and parking_str.count('True') > parking_str.count('False'):
                has_business = True
            # If actual dict
            elif isinstance(business_parking, dict):
                for k, v in business_parking.items():
                    if str(v).lower() == 'true':
                        has_business = True
                        break

    if has_bike or has_business:
        results.append({
            'business_id': business_id,
            'name': business.get('name', 'Unknown'),
            'has_bike_parking': has_bike,
            'has_business_parking': has_business
        })

print(f"\nBusinesses reviewed in 2018 that offer parking: {len(results)}")
for r in results:
    print(f"  {r['business_id']}: {r['name']}")

missing_ids = unique_business_ids_2018 - set(business_by_id.keys())
print(f"\nMissing business IDs (need to fetch): {len(missing_ids)}")
if len(missing_ids) > 0:
    print(f"  {sorted(list(missing_ids))}")

result = {
    "total_reviewed_2018": len(unique_business_ids_2018),
    "with_parking": len(results),
    "missing": len(missing_ids),
    "parking_businesses": results
}

print('__RESULT__:')
print(json.dumps(result))"}

